/* main.min.js - SİMAK VİNÇ MANİTOU */
document.addEventListener("DOMContentLoaded", function() {
  // Header sticky & Scroll-to-top button
  var header = document.getElementById("site-header");
  var menuToggle = document.getElementById("mobile-menu-toggle");
  var mainNav = document.getElementById("main-nav");
  var scrollTopBtn = document.getElementById("scroll-top");

  var scrollCheckDelay = false;
  function checkSticky() {
    if (scrollCheckDelay) return;
    scrollCheckDelay = true;
    
    requestAnimationFrame(function() {
      if (window.scrollY > 10) {
        header && header.classList.add("sticky");
      } else {
        header && header.classList.remove("sticky");
      }
      // Scroll-to-top button visibility
      if (scrollTopBtn) {
        if (window.scrollY > 400) {
          scrollTopBtn.classList.add("visible");
        } else {
          scrollTopBtn.classList.remove("visible");
        }
      }
      scrollCheckDelay = false;
    });
  }
  window.addEventListener("scroll", checkSticky, { passive: true });
  // İlk kontrolü geciktir - sayfa tamamen yüklensin
  setTimeout(checkSticky, 100);

  // Scroll-to-top click handler
  if (scrollTopBtn) {
    scrollTopBtn.addEventListener("click", function() {
      window.scrollTo({ top: 0, behavior: "smooth" });
    });
  }

  // Mobile menu toggle
  if (menuToggle && mainNav) {
    function toggleMenu(e) {
      e.preventDefault();
      e.stopPropagation();
      
      var isExpanded = menuToggle.getAttribute("aria-expanded") === "true";
      var navList = mainNav.querySelector("ul");
      
      menuToggle.setAttribute("aria-expanded", String(!isExpanded));
      
      if (navList) {
        if (isExpanded) {
          navList.classList.remove("open");
          navList.setAttribute("aria-hidden", "true");
          document.body.classList.remove("menu-open");
        } else {
          navList.classList.add("open");
          navList.setAttribute("aria-hidden", "false");
          document.body.classList.add("menu-open");
        }
      }
    }
    
    menuToggle.addEventListener("click", toggleMenu);
    menuToggle.addEventListener("touchend", function(e) {
      e.preventDefault();
      toggleMenu(e);
    });

    // Close menu when clicking outside
    document.addEventListener("click", function(e) {
      var navList = mainNav.querySelector("ul");
      if (navList && navList.classList.contains("open")) {
        if (!mainNav.contains(e.target) && !menuToggle.contains(e.target)) {
          navList.classList.remove("open");
          navList.setAttribute("aria-hidden", "true");
          menuToggle.setAttribute("aria-expanded", "false");
          document.body.classList.remove("menu-open");
        }
      }
    });

    // Close menu on Escape
    document.addEventListener("keydown", function(e) {
      if (e.key === "Escape" || e.key === "Esc") {
        var navList = mainNav.querySelector("ul");
        if (navList && navList.classList.contains("open")) {
          navList.classList.remove("open");
          navList.setAttribute("aria-hidden", "true");
          menuToggle.setAttribute("aria-expanded", "false");
          document.body.classList.remove("menu-open");
          menuToggle.focus();
        }
      }
    });

    // Close menu when clicking nav links
    var navLinks = mainNav.querySelectorAll("ul li a");
    for (var i = 0; i < navLinks.length; i++) {
      navLinks[i].addEventListener("click", function() {
        var navList = mainNav.querySelector("ul");
        if (navList && navList.classList.contains("open")) {
          navList.classList.remove("open");
          navList.setAttribute("aria-hidden", "true");
          menuToggle.setAttribute("aria-expanded", "false");
          document.body.classList.remove("menu-open");
        }
      });
    }

    // Close menu on window resize to desktop
    window.addEventListener("resize", function() {
      if (window.innerWidth > 700) {
        var navList = mainNav.querySelector("ul");
        if (navList && navList.classList.contains("open")) {
          navList.classList.remove("open");
          navList.setAttribute("aria-hidden", "true");
          menuToggle.setAttribute("aria-expanded", "false");
          document.body.classList.remove("menu-open");
        }
      }
    });
  }

  // Smooth scroll for anchor links
  var anchorLinks = document.querySelectorAll('a[href^="#"]');
  for (var i = 0; i < anchorLinks.length; i++) {
    anchorLinks[i].addEventListener("click", function(e) {
      var href = this.getAttribute("href");
      if (href && href.startsWith("#") && href.length > 1) {
        e.preventDefault();
        var target = document.querySelector(href);
        if (target) target.scrollIntoView({ behavior: "smooth" });
      }
    });
  }

  // Contact form
  var contactForm = document.getElementById("contactForm");
  if (contactForm) {
    contactForm.addEventListener("submit", function(e) {
      e.preventDefault();
      var inputs = contactForm.querySelectorAll("input, textarea");
      var valid = true;
      for (var j = 0; j < inputs.length; j++) {
        if (!inputs[j].value.trim()) {
          inputs[j].classList.add("error");
          valid = false;
        } else {
          inputs[j].classList.remove("error");
        }
      }
      var msg = document.getElementById("formMessage");
      if (valid) {
        if (msg) msg.textContent = "Mesajınız gönderiliyor...";
        setTimeout(function() {
          if (msg) msg.textContent = "Mesajınız başarıyla gönderildi.";
          contactForm.reset();
        }, 900);
      } else {
        if (msg) msg.textContent = "Lütfen tüm alanları doldurun.";
      }
    });
  }

  // Lazy load images
  var lazyImages = document.querySelectorAll('img[loading="lazy"]');
  for (var k = 0; k < lazyImages.length; k++) {
    (function(img) {
      if (img.complete) {
        img.classList.add("loaded");
      } else {
        img.addEventListener("load", function() {
          img.classList.add("loaded");
        });
      }
    })(lazyImages[k]);
  }

  // Accordion
  var accordionBtns = document.querySelectorAll(".accordion-toggle");
  for (var m = 0; m < accordionBtns.length; m++) {
    accordionBtns[m].addEventListener("click", function() {
      var expanded = this.getAttribute("aria-expanded") === "true";
      this.setAttribute("aria-expanded", String(!expanded));
      var panel = this.nextElementSibling;
      if (panel) panel.classList.toggle("open");
    });
  }

  // Hero image loaded
  var heroImg = document.querySelector(".hero-media img.hero-img");
  if (heroImg) {
    function markLoaded() {
      heroImg.classList.add("loaded");
    }
    if (heroImg.complete && heroImg.naturalWidth > 10) {
      markLoaded();
    } else {
      heroImg.addEventListener("load", markLoaded);
    }
  }

  // Hero video: lazy load on capable devices only
  var heroVideo = document.getElementById("hero-video");
  if (heroVideo) {
    var isSmallScreen = window.matchMedia && window.matchMedia("(max-width: 700px)").matches;
    var conn = navigator.connection || navigator.mozConnection || navigator.webkitConnection;
    var isDataSaver = !!(conn && (conn.saveData || /2g/.test(conn.effectiveType || "")));
    var canLoadVideo = !isSmallScreen && !isDataSaver;

    var loadHeroVideo = function() {
      if (heroVideo.dataset.loaded === "true") return;
      var source = heroVideo.querySelector("source[data-src]");
      if (source && !source.getAttribute("src")) {
        source.setAttribute("src", source.getAttribute("data-src"));
      }
      heroVideo.load();
      var playPromise = heroVideo.play();
      if (playPromise && typeof playPromise.catch === "function") {
        playPromise.catch(function() {});
      }
      heroVideo.dataset.loaded = "true";
    };

    if (canLoadVideo) {
      if ("IntersectionObserver" in window) {
        var heroObserver = new IntersectionObserver(function(entries) {
          if (entries[0] && entries[0].isIntersecting) {
            loadHeroVideo();
            heroObserver.disconnect();
          }
        }, { rootMargin: "200px" });
        heroObserver.observe(heroVideo);
      } else {
        loadHeroVideo();
      }
    } else {
      heroVideo.removeAttribute("autoplay");
      heroVideo.pause();
    }
  }

  // Lightbox
  var lightbox = document.getElementById("lightbox");
  var lbImage = lightbox ? lightbox.querySelector(".lb-image") : null;
  var lbCaption = lightbox ? lightbox.querySelector(".lb-caption") : null;
  var lbClose = lightbox ? lightbox.querySelector(".lb-close") : null;
  var lbPrev = lightbox ? lightbox.querySelector(".lb-prev") : null;
  var lbNext = lightbox ? lightbox.querySelector(".lb-next") : null;
  var galleryItems = document.querySelectorAll(".gallery-item");
  var lightboxEnabled = !!(lightbox && lbImage);
  var currentIndex = 0;
  var images = [];

  for (var n = 0; n < galleryItems.length; n++) {
    var item = galleryItems[n];
    var link = item.tagName === "A" ? item : item.querySelector("a");
    var img = item.querySelector("img");
    var primary = link ? link.getAttribute("href") : "";
    var fullSrc = (img && img.dataset ? img.dataset.full : "") || (link && link.dataset ? link.dataset.full : "") || primary;
    var fallbackSrc = primary || (img ? img.getAttribute("src") : "");

    if (link && (primary || fullSrc)) {
      images.push({
        src: fullSrc || fallbackSrc,
        fallback: fallbackSrc,
        caption: link.dataset.caption || (img ? img.alt : ""),
        el: link
      });
    } else if (img) {
      images.push({
        src: fullSrc || img.getAttribute("src"),
        fallback: img.getAttribute("src"),
        caption: img.alt || "",
        el: item
      });
    }
  }

  function openLightbox(index) {
    if (!lightboxEnabled) return;
    currentIndex = index;
    var item = images[currentIndex];
    if (!item || !lbImage) return;

    var targetSrc = item.src || item.fallback;
    var fallbackSrc = item.fallback || item.src;

    lightbox.setAttribute("aria-hidden", "false");
    lightbox.style.display = "flex";
    document.body.classList.add("modal-open");

    lbImage.onload = function() {
      lbImage.classList.remove("anim-out-left", "anim-out-right");
    };
    lbImage.onerror = function() {
      if (fallbackSrc && lbImage.src !== fallbackSrc) {
        lbImage.src = fallbackSrc;
        return;
      }
    };

    lbImage.src = targetSrc;
    lbImage.alt = item.caption || "";

    if (lbCaption) {
      var hasCaption = !!item.caption;
      lbCaption.textContent = item.caption || "";
      lbCaption.hidden = !hasCaption;
      lbCaption.setAttribute("aria-hidden", hasCaption ? "false" : "true");
    }
  }

  function closeLightbox() {
    if (!lightbox) return;
    lightbox.setAttribute("aria-hidden", "true");
    lightbox.style.display = "none";
    document.body.classList.remove("modal-open");
    if (lbImage) lbImage.src = "";
  }

  function nextImage() {
    currentIndex = (currentIndex + 1) % images.length;
    openLightbox(currentIndex);
  }

  function prevImage() {
    currentIndex = (currentIndex - 1 + images.length) % images.length;
    openLightbox(currentIndex);
  }

  for (var p = 0; p < images.length; p++) {
    (function(index) {
      var el = images[index].el;
      if (!el) return;
      el.addEventListener("click", function(e) {
        if (!lightboxEnabled) return;
        e.preventDefault();
        openLightbox(index);
      });
    })(p);
  }

  if (lbClose) lbClose.addEventListener("click", closeLightbox);
  if (lbPrev) lbPrev.addEventListener("click", prevImage);
  if (lbNext) lbNext.addEventListener("click", nextImage);

  document.addEventListener("keydown", function(e) {
    if (lightbox && lightbox.getAttribute("aria-hidden") === "false") {
      if (e.key === "ArrowRight") nextImage();
      if (e.key === "ArrowLeft") prevImage();
      if (e.key === "Escape") closeLightbox();
    }
  });

  if (lightbox) {
    lightbox.addEventListener("click", function(e) {
      if (e.target === lightbox) closeLightbox();
    });
    
    // Touch/swipe support
    var touchStartX = 0;
    lightbox.addEventListener("touchstart", function(e) {
      touchStartX = e.changedTouches[0].screenX;
    }, {passive: true});
    
    lightbox.addEventListener("touchend", function(e) {
      var touchEndX = e.changedTouches[0].screenX;
      var diff = touchEndX - touchStartX;
      if (Math.abs(diff) > 50) {
        if (diff < 0) {
          nextImage();
        } else {
          prevImage();
        }
      }
    }, {passive: true});
  }

  // WebP desteği varsa tüm JPEG görselleri WebP'ye yönlendir
  (function(){
    function testWebP(cb){
      var img=new Image();
      img.onload=function(){cb(img.width===1);};
      img.onerror=function(){cb(false);};
      img.src="data:image/webp;base64,UklGRiIAAABXRUJQVlA4TCEAAAAvAAAAAAfQ//73v/+BiOh/AAA=";
    }
    function swapNodeToWebP(node){
      var src=node.getAttribute("src");
      if(src && /\.jpe?g$/i.test(src)) node.setAttribute("src", src.replace(/\.jpe?g$/i, ".webp"));
      var srcset=node.getAttribute("srcset");
      if(srcset && /\.jpe?g/i.test(srcset)) node.setAttribute("srcset", srcset.replace(/\.jpe?g/gi, ".webp"));
    }
    testWebP(function(ok){
      if(!ok) return;
      var imgs=document.querySelectorAll("img");
      for(var i=0;i<imgs.length;i++){ swapNodeToWebP(imgs[i]); }
      var sources=document.querySelectorAll("source[srcset]");
      for(var j=0;j<sources.length;j++){
        var set=sources[j].getAttribute("srcset");
        if(set && /\.jpe?g/i.test(set)) sources[j].setAttribute("srcset", set.replace(/\.jpe?g/gi, ".webp"));
      }
    });
  })();
});
